package ingest

import (
	"strings"
	"testing"
)

func TestParseSimpleDocument(t *testing.T) {
	content := `# Document Title

## A.1 - First Section

Content of first section.

### Subsection

More content.

## A.2 - Second Section

Content of second section.

## A.3 - Third Section

Content of third section.
`

	chunks := Parse("docs/test-doc.md", content, ParseOptions{
		Scope: "global",
		Kind:  "reference",
	})

	if len(chunks) != 3 {
		t.Fatalf("expected 3 chunks, got %d", len(chunks))
	}

	// First chunk
	if chunks[0].SectionID != "A.1" {
		t.Errorf("chunk[0].SectionID = %q, want %q", chunks[0].SectionID, "A.1")
	}
	if chunks[0].Title != "First Section" {
		t.Errorf("chunk[0].Title = %q, want %q", chunks[0].Title, "First Section")
	}
	if chunks[0].QualifiedID != "test-doc:A.1" {
		t.Errorf("chunk[0].QualifiedID = %q, want %q", chunks[0].QualifiedID, "test-doc:A.1")
	}
	if chunks[0].Scope != "global" {
		t.Errorf("chunk[0].Scope = %q, want %q", chunks[0].Scope, "global")
	}
	if chunks[0].Kind != "reference" {
		t.Errorf("chunk[0].Kind = %q, want %q", chunks[0].Kind, "reference")
	}
	// ### should be included in parent
	if !strings.Contains(chunks[0].Content, "Subsection") {
		t.Error("### content should be included in parent ## chunk")
	}

	// Position should be sequential
	for i, c := range chunks {
		if c.Position != i {
			t.Errorf("chunk[%d].Position = %d, want %d", i, c.Position, i)
		}
	}
}

func TestParseFrontMatterOverride(t *testing.T) {
	content := `---
title: "My Decision"
kind: decision
scope: global
tags: [embedding, model]
---

## Context

Some context.

## Decision

The decision.
`

	chunks := Parse("docs/decision.md", content, ParseOptions{
		Scope: "project",
		Kind:  "reference",
	})

	if len(chunks) != 2 {
		t.Fatalf("expected 2 chunks, got %d", len(chunks))
	}

	// Front matter should override parameters
	if chunks[0].Kind != "decision" {
		t.Errorf("kind = %q, want %q (front matter override)", chunks[0].Kind, "decision")
	}
	if chunks[0].Scope != "global" {
		t.Errorf("scope = %q, want %q (front matter override)", chunks[0].Scope, "global")
	}
	if len(chunks[0].Tags) != 2 {
		t.Errorf("tags = %v, want 2 tags", chunks[0].Tags)
	}
}

func TestParseNoHeaders(t *testing.T) {
	content := `Just some content without any headers.

This is a paragraph.

And another one.`

	chunks := Parse("docs/flat.md", content, ParseOptions{
		Scope: "project",
		Kind:  "reference",
	})

	if len(chunks) != 1 {
		t.Fatalf("expected 1 chunk for no-header doc, got %d", len(chunks))
	}
	if chunks[0].SectionID != "content" {
		t.Errorf("sectionID = %q, want %q", chunks[0].SectionID, "content")
	}
}

func TestParseSubSplitting(t *testing.T) {
	// Create a section with content > maxChunkSize
	var longContent strings.Builder
	longContent.WriteString("## Big Section\n\n")
	for i := 0; i < 100; i++ {
		longContent.WriteString("This is a paragraph of reasonable length to test splitting. ")
		longContent.WriteString("It contains enough text to be meaningful.\n\n")
	}

	chunks := Parse("docs/long.md", longContent.String(), ParseOptions{
		MaxChunkSize: 500,
		Scope:        "project",
		Kind:         "reference",
	})

	if len(chunks) < 2 {
		t.Fatalf("expected multiple chunks from sub-splitting, got %d", len(chunks))
	}

	// Verify sub-split IDs
	if !strings.Contains(chunks[0].SectionID, "#1") {
		t.Errorf("first sub-split should have #1, got %q", chunks[0].SectionID)
	}
}

func TestParseDocumentSlug(t *testing.T) {
	content := `## Section One

Content.`

	chunks := Parse("docs/My Document.md", content, ParseOptions{
		Scope: "project",
		Kind:  "reference",
	})

	if len(chunks) == 0 {
		t.Fatal("expected at least 1 chunk")
	}
	if chunks[0].DocumentSlug != "my-document" {
		t.Errorf("DocumentSlug = %q, want %q", chunks[0].DocumentSlug, "my-document")
	}
}

func TestParseEmptyContent(t *testing.T) {
	chunks := Parse("docs/empty.md", "", ParseOptions{
		Scope: "project",
		Kind:  "reference",
	})

	if len(chunks) != 0 {
		t.Errorf("expected 0 chunks for empty content, got %d", len(chunks))
	}
}

func TestParseTagsNeverNil(t *testing.T) {
	content := `## Section

Content without front matter.`

	chunks := Parse("docs/no-tags.md", content, ParseOptions{
		Scope: "project",
		Kind:  "reference",
	})

	if len(chunks) == 0 {
		t.Fatal("expected at least 1 chunk")
	}
	if chunks[0].Tags == nil {
		t.Error("Tags should never be nil, should be empty slice")
	}
}
